metadata.preview:
.saved-power {
    color: var(--accent-green);
}

.device-savings {
    font-size: 0.95em;
    font-weight: bold;
    min-width: 60px;
    text-align: right;
}

.device-savings.positive {
    color: var(--accent-green);
}

.device-savings.negative {
    color: var(--accent-red);
}
